CVE-2026-21262.script:
# Détection par KB correctif : CVE-2026-21262
# Les KB listés couvrent plusieurs versions de Windows ; une machine n'en
# installe qu'UN (celui de son OS). Donc : protégé dès qu'UN correctif est présent.
$kbCorrecifs = @("KB5077472", "KB5077470", "KB5077474", "KB5077471", "KB5077473", "KB5077465", "KB5077468", "KB5077469", "KB5077464", "KB5077466")
$Session  = New-Object -ComObject Microsoft.Update.Session
$Searcher = $Session.CreateUpdateSearcher()
$Updates  = $Searcher.Search("IsInstalled=1").Updates
$installes = $Updates | ForEach-Object { $_.KBArticleIDs } | ForEach-Object { "KB$_" }
$presents = $kbCorrecifs | Where-Object { $installes -contains $_ }
if ($presents.Count -gt 0) {
    Write-Host "✅ PROTÉGÉ   - CVE-2026-21262 : correctif présent ($($presents -join ', '))" -ForegroundColor Green
} else {
    Write-Host "⚠️  VULNÉRABLE - CVE-2026-21262 : aucun correctif installé (ou CVE non applicable à cet OS)" -ForegroundColor Red
}

